{
  "slots": [
    { "id": "heights", "type": "array", "label": "Heights (Bar Chart)", "display": "bar" },
    { "id": "vars", "type": "hashmap", "label": "State Variables" }
  ],
  "inputs": [
    { "label": "Heights (comma separated)", "default": "1,8,6,2,5,4,8,3,7" }
  ],
  "code": "class Playground {
  async run(inputs) {
    const h = inputs[0].split(',').map(Number);
    await this.heights.init(h);
    await this.vars.init([
      ["left", 0],
      ["right", h.length - 1],
      ["maxArea", 0],
      ["currentArea", 0]
    ]);

    let left = 0;
    let right = h.length - 1;
    let maxArea = 0;

    while (left < right) {
      // Highlight the two bars being considered
      this.heights.highlight(left, "#00e0ff");
      this.heights.highlight(right, "#ffb703");

      const hL = h[left];
      const hR = h[right];
      const width = right - left;
      const currentArea = Math.min(hL, hR) * width;

      if (currentArea > maxArea) {
        maxArea = currentArea;
      }

      this.vars.put("left", left);
      this.vars.put("right", right);
      this.vars.put("currentArea", currentArea);
      this.vars.put("maxArea", maxArea);

      this.log(`Left height: ${hL}, Right height: ${hR}. Width: ${width}. Area: ${currentArea}`);
      await this.await();

      this.heights.highlight(left, null);
      this.heights.highlight(right, null);

      // Greedy step: Move the shorter pointer
      if (hL < hR) {
        this.log(`Left wall (${hL}) is shorter than Right wall (${hR}). Moving Left pointer right.`);
        left++;
      } else {
        this.log(`Right wall (${hR}) is shorter than or equal to Left wall (${hL}). Moving Right pointer left.`);
        right--;
      }
    }

    this.log(`Search complete. Maximum area found: ${maxArea}`);
    return maxArea;
  }
}"
}

{
  "slots": [
    { "id": "list", "type": "sll", "label": "Singly Linked List" },
    { "id": "vars", "type": "hashmap", "label": "Pointers & State" }
  ],
  "inputs": [
    { "label": "List Values", "default": "1,2,3,4,5" }
  ],
  "code": "class Playground {
  async run(inputs) {
    const vals = inputs[0].split(',').map(v => v.trim());
    await this.list.init(vals);
    await this.vars.init([]);

    let prevId = null;
    let currId = this.list.getHeadId();

    this.list.createPointer('curr', currId, '#00e0ff');
    this.vars.put('prev', 'null');
    this.log('Starting reversal. prev is null, curr is at head.');
    await this.await();

    while (currId !== null) {
      // 1. Save next
      let nextId = this.list.getNextId(currId);
      this.vars.put('next', nextId || 'null');
      this.log('Step 1: Save the next node reference.');
      await this.await();

      // 2. Reverse the link
      this.log('Step 2: Reverse the pointer (curr.next = prev).');
      this.list.unlink(currId, 'next');
      if (prevId !== null) {
        this.list.link(currId, prevId, 'next');
      }
      this.list.highlightNode(currId, '#00f5a0');
      await this.await();

      // 3. Move pointers forward
      this.log('Step 3: Move prev and curr forward.');
      prevId = currId;
      currId = nextId;

      this.vars.put('prev', prevId);
      if (currId) {
        this.list.movePointer('curr', currId);
      } else {
        this.list.removePointer('curr');
      }
      await this.await();
    }

    this.log('Reversal complete! The list is now fully reversed.');
    return 'New Head ID: ' + prevId;
  }
}"
}

{
  "slots": [
    { "id": "tree", "type": "binary_tree", "label": "Binary Tree" },
    { "id": "path", "type": "array", "label": "Current Path" },
    { "id": "results", "type": "array", "label": "All Found Paths" },
    { "id": "callstack", "type": "callstack", "label": "DFS Call Stack" },
    { "id": "recursionTree", "type": "recursion_tree", "label": "Recursion Visualization" }
  ],
  "inputs": [
    { "label": "Tree Array (LeetCode format)", "default": "[1, 2, 3, null, 5, 6]" }
  ],
  "code": "class Playground {
  async run(inputs) {
    const vals = JSON.parse(inputs[0] || '[1, 2, 3, null, 5, 6]');
    this.tree.init(vals);
    this.path.init([]);
    this.results.init([]);
    this.callstack.init();
    this.recursionTree.init();

    const root = this.tree.getRoot();
    if (!root) return [];

    await this.dfs(root);
    return this.results.getValues();
  }

  async dfs(node) {
    if (!node) return;

    const nodeId = node.id;
    const nodeVal = node.val;

    this.callstack.pushFrame('dfs', { node: nodeVal });
    this.recursionTree.enterNode(nodeId, `Node ${nodeVal}`);
    this.tree.highlight(nodeId, '#00e0ff');
    this.path.push(nodeVal);

    this.log(`Visiting node ${nodeVal}. Current path: ${this.path.getValues().join(' -> ')}`);
    await this.await();

    const isLeaf = !node.left && !node.right;

    if (isLeaf) {
      const fullPath = this.path.getValues().join('->');
      this.results.push(fullPath);
      this.log(`Leaf reached! Recorded path: ${fullPath}`);
      this.tree.highlight(nodeId, '#00f5a0');
      await this.await();
    } else {
      if (node.left) {
        await this.dfs(node.left);
      }
      if (node.right) {
        await this.dfs(node.right);
      }
    }

    this.path.pop();
    this.tree.highlight(nodeId, null);
    this.log(`Backtracking from node ${nodeVal}`);
    this.recursionTree.exitNode();
    this.callstack.popFrame();
    await this.await();
  }
}"
}

